            # Parse duration, defaulting to 0 if missing
            $duration = 0.0
            if ($tc.time) {
                $duration = [double]$tc.time
            }

            $null = $tests.Add(@{
                Name     = $tc.name
                Suite    = if ($tc.classname) { $tc.classname } else { $suite.name }
                Status   = $status
                Duration = $duration
                Error    = $errorMsg
            })

            switch ($status) {
                'passed'  { $totalPassed++ }
                'failed'  { $totalFailed++ }
